    for i in 64..83 {
        assert(hash_prefix[i - 64] == padded_sha512_hash[i]);
    }

    assert(padded_sha512_hash[83] == 0);

    // Sub 64 bytes for hash, 19 bytes for prefix, 1 byte for 0, 1 byte for 1, 1 byte for 0
    let ps_len = N - 86;
    for i in 84..N {
        if i as u32 < 84 + ps_len as u32 {
